package com.aliat.alm.models;



public class AgentAreaBorder {
	 String lng;

	 String lat;

	public AgentAreaBorder() {
		super();
		// TODO Auto-generated constructor stub
	}

	public AgentAreaBorder(String lng, String lat) {
		super();
		this.lng = lng;
		this.lat = lat;
	}

	public String getLng() {
		return lng;
	}

	public void setLng(String lng) {
		this.lng = lng;
	}

	public String getLat() {
		return lat;
	}

	public void setLat(String lat) {
		this.lat = lat;
	}


	

}
